// Spring Boot + Resilience4j — retry + circuit breaker + timeout on ONE downstream.
// build.gradle: implementation 'io.github.resilience4j:resilience4j-spring-boot3:2.2.0'

@Service
public class InventoryClient {
  private final RestClient http;

  public InventoryClient(RestClient.Builder builder) {
    this.http = builder
        .baseUrl("http://inventory-service:8080")
        .requestFactory(new SimpleClientHttpRequestFactory() {{
          setConnectTimeout(500);   // 500ms connect
          setReadTimeout(2000);      // 2s read — TIMEOUT is defense #1
        }})
        .build();
  }

  @CircuitBreaker(name = "inventory", fallbackMethod = "reserveFallback")
  @Retry(name = "inventory")
  @TimeLimiter(name = "inventory")
  public CompletableFuture<ReservationResult> reserve(String sku, int qty) {
    return CompletableFuture.supplyAsync(() ->
      http.post()
         .uri("/reservations")
         .body(Map.of("sku", sku, "qty", qty))
         .retrieve()
         .body(ReservationResult.class));
  }

  // Fallback: what to do when inventory is completely unreachable?
  // Options: return degraded response, queue for retry, throw controlled exception.
  private CompletableFuture<ReservationResult> reserveFallback(String sku, int qty, Throwable t) {
    log.warn("Inventory unreachable — queuing reservation for retry", t);
    outboxRepository.save(new PendingReservation(sku, qty));
    return CompletableFuture.completedFuture(ReservationResult.pending());
  }
}

